class Solution:
    def countHomogenous(self, s):
        MOD = 10 ** 9 + 7
        total = 0
        run = 0
        prev = ''
        for ch in s:
            if ch == prev:
                run += 1
            else:
                run = 1
                prev = ch
            total += run
        return total % MOD

