var countHomogenous = function(s) {
    const MOD = 1000000007n;
    let total = 0n;
    let run = 0n;
    let prev = '';
    for (const ch of s) {
        if (ch === prev) run += 1n;
        else { run = 1n; prev = ch; }
        total += run;
    }
    return Number(total % MOD);
};
